// Function to generate a random integer between min (inclusive) and max (inclusive)
function getRandomInt(min, max) {
  // Ensure inputs are integers
  min = Math.ceil(min);
  max = Math.floor(max);
  // Math.random() gives [0, 1). Multiply by range size, floor, add min.
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

// Generate a random float between 0 (inclusive) and 1 (exclusive)
const randomFloatZeroToOne = Math.random();

// Generate a random float within a specific range [min, max)
function getRandomFloat(min, max) {
    return Math.random() * (max - min) + min;
}


// Example Usage
const minVal = 1;
const maxVal = 100;
const randomInt = getRandomInt(minVal, maxVal);
console.log(`Random integer (${minVal}-${maxVal}): ${randomInt}`); 

console.log(`Random float [0, 1): ${randomFloatZeroToOne}`); 

const floatMin = 10.0;
const floatMax = 20.0;
const randomFloatRange = getRandomFloat(floatMin, floatMax);
console.log(`Random float [${floatMin}, ${floatMax}): ${randomFloatRange}`);

