function generateFibonacci(n) {
  if (typeof n !== 'number' || !Number.isInteger(n) || n <= 0) {
    console.error("Input must be a positive integer.");
    return [];
  }

  const sequence = [];
  let a = 0, b = 1;

  for (let i = 0; i < n; i++) {
    sequence.push(a);
    // Use array destructuring for a concise swap (ES6+)
    [a, b] = [b, a + b];

    // Note: JavaScript numbers are 64-bit floats. Large Fibonacci numbers
    // will lose precision or become Infinity beyond Number.MAX_SAFE_INTEGER.
    // For very large numbers, use BigInt (add 'n' suffix to numbers).
  }
  return sequence;
}

// Example Usage
const numTerms = 10;
const fibNumbers = generateFibonacci(numTerms);
console.log(`Fibonacci Sequence (first ${numTerms} terms):`); 
console.log(fibNumbers); // Output the array
console.log(fibNumbers.join(', ')); // Output as comma-separated string

