function factorial(n) {
  if (typeof n !== 'number' || !Number.isInteger(n) || n < 0) {
    console.error("Factorial is only defined for non-negative integers.");
    return null; // Or throw RangeError
  }
  if (n === 0) {
    return 1;
  }

  let result = 1;
  for (let i = 2; i <= n; i++) {
    result *= i;
    // JavaScript numbers are floats; precision issues and Infinity occur for large n.
    // result becomes Infinity around n=171.
    // Use BigInt for factorials of larger numbers.
  }
  return result;
}

// Example Usage
console.log(`Factorial of 5 = ${factorial(5)}`); // 120
console.log(`Factorial of 0 = ${factorial(0)}`); // 1
console.log(`Factorial of 20 = ${factorial(20)}`); // 2432902008176640000

