function isPrime(n) {
  if (typeof n !== 'number' || !Number.isInteger(n)) {
      console.error("Input must be an integer.");
      return false; // Or throw TypeError
  }

  if (n <= 1) return false; // Numbers <= 1 are not prime
  if (n <= 3) return true;  // 2 and 3 are prime

  // Eliminate multiples of 2 and 3 early
  if (n % 2 === 0 || n % 3 === 0) return false;

  // Check factors from 5 upwards, stepping by 6
  // Only need to check up to the square root of n
  const limit = Math.sqrt(n);
  for (let i = 5; i <= limit; i += 6) {
    if (n % i === 0 || n % (i + 2) === 0) {
      return false;
    }
  }

  return true; // If no divisors found, it's prime
}

// Example Usage
const numbersToCheck = [0, 1, 2, 3, 4, 17, 25, 29, 97, 100, -5, 104729];

numbersToCheck.forEach(num => {
  if (isPrime(num)) {
    console.log(`${num} is a prime number.`); 
  } else {
    console.log(`${num} is not a prime number.`); 
  }
});

