// --- Node.js REQUIRED for file system access ---

// Method 1: Using fs/promises (Recommended - Async/Await)
async function readFileAsync(filename = "example_js.txt") {
  // Requires Node.js v14+ or v10+ (now stable)
  const fs = require('fs').promises; // Use the promises API
  const path = require('path');

  console.log(`--- Reading file (async): ${filename} ---`); 
  try {
    // Read the entire file content as a UTF-8 string
    const data = await fs.readFile(filename, { encoding: 'utf8' });
    console.log("File Content:");
    console.log(data);
    return data;
  } catch (err) {
    console.error(`Error reading file: ${err.message}`); 
    if (err.code === 'ENOENT') {
        console.error("Hint: File not found.");
    }
    return null;
  }
}

// Method 2: Using fs.readFileSync (Synchronous - Blocks execution)
function readFileSync(filename = "example_js.txt") {
  const fs = require('fs');
  const path = require('path');

  console.log(`\n--- Reading file (sync): ${filename} ---`); 
  try {
    // Read the entire file content synchronously
    const data = fs.readFileSync(filename, { encoding: 'utf8' });
    console.log("File Content:");
    console.log(data);
    return data;
  } catch (err) {
    console.error(`Error reading file sync: ${err.message}`); 
    return null;
  }
}


