// --- Node.js REQUIRED for file system access ---

const fs = require('fs').promises;

// Checks if a path exists and whether it's a file or directory.
async function checkPath(filepath) {
  try {
    const stats = await fs.stat(filepath);
    if (stats.isFile()) {
      console.log(`'${filepath}' exists and is a FILE.`);
    } else if (stats.isDirectory()) {
      console.log(`'${filepath}' exists and is a DIRECTORY.`);
    }
  } catch (err) {
    if (err.code === 'ENOENT') {
      console.log(`'${filepath}' does NOT exist.`);
    } else {
      console.error(`Error checking '${filepath}':`, err.message);
    }
  }
}

// --- How to run this example ---
// 1. Save the code as a .js file (e.g., existsExample.js).
// 2. Run from your terminal: node existsExample.js
async function runExistsChecks() {
    console.log("--- Checking Paths ---");
    // Create dummy file/dir for the check
    await fs.writeFile('dummy_file.txt', 'content');
    await fs.mkdir('dummy_dir', { recursive: true });

    await checkPath('dummy_file.txt');
    await checkPath('dummy_dir');
    await checkPath('non_existent_file.xyz');

    // Cleanup
    await fs.unlink('dummy_file.txt');
    await fs.rmdir('dummy_dir');
}

