console.log(`Month: ${month} (0-indexed, so add 1 for display: ${month + 1})`); 
console.log(`Day: ${day}`); 
console.log(`Hours: ${hours}`); 

// 3. Formatting Dates
// Basic built-in methods (locale-dependent output)
console.log(`Locale Date String: ${now.toLocaleDateString()}`);
console.log(`Locale Time String: ${now.toLocaleTimeString()}`);

// ISO 8601 Standard Format (good for interchange)
console.log(`ISO String (UTC): ${now.toISOString()}`);  // e.g., "2025-07-17T15:04:18.123Z"

// Intl.DateTimeFormat (Modern, powerful, locale-aware formatting)
const options = { 
    year: 'numeric', month: 'long', day: 'numeric', 
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    timeZoneName: 'short' 
};
const formatter = new Intl.DateTimeFormat('en-US', options);
console.log(`Intl Format (en-US): ${formatter.format(now)}`);

// 4. Get Timestamp (Milliseconds since epoch UTC)
