function findMaxInArray(arr) {
  if (!Array.isArray(arr) || arr.length === 0) {
    // Return a value or throw an error for invalid/empty arrays
    return undefined;
  }

  // Method 1: Using Math.max() with the spread operator (...)
  // This is concise but can fail with very large arrays due to stack limits.
  // return Math.max(...arr);

  // Method 2: Using reduce() - More robust for large arrays
  return arr.reduce((max, current) => {
    // Ensure elements are numbers, otherwise comparison is lexicographical
    const numCurrent = Number(current);
    return numCurrent > max ? numCurrent : max;
  }, -Infinity); // Initialize with the lowest possible number
}

// Example Usage
const numbers = [10, 5, 42, 17, 8, 99, 32, -5, 0];
console.log(`Array: [${numbers.join(', ')}]`); 
const maximum = findMaxInArray(numbers);
console.log(`Maximum value: ${maximum}`);  // 99

const emptyArray = [];
console.log(`\nArray: []`); 
const maxEmpty = findMaxInArray(emptyArray);
console.log(`Maximum value: ${maxEmpty}`);  // undefined

const mixedArray = [10, 5, 'a', 99]; // Contains a non-number string
console.log(`\nArray: [${mixedArray.join(', ')}]`); 
const maxMixed = findMaxInArray(mixedArray);
console.log(`Maximum value: ${maxMixed}`);  // 99 ('a' is treated as NaN, which is not > 99)
